#!/usr/bin/env bash
# apply_fix.sh — Full PDFium migration + CI fixes for PDF_Editor3
# Usage: bash apply_fix.sh [/path/to/PDF_Editor3]
# Omit the path to operate on the current directory.

set -euo pipefail

REPO="${1:-$(pwd)}"

if [ ! -f "$REPO/pubspec.yaml" ]; then
  echo "ERROR: $REPO is not a Flutter project (pubspec.yaml not found)."
  exit 1
fi

echo "Applying PDFium migration + CI fixes to: $REPO"

# ── Backup ───────────────────────────────────────────────────────────────────
BACKUP="$(dirname "$REPO")/_backup_$(basename "$REPO")_pdfium_$(date +%Y%m%d_%H%M%S)"
echo "Creating backup at: $BACKUP"
cp -r "$REPO" "$BACKUP"
echo "Backup created."

# ── Create directories ───────────────────────────────────────────────────────
mkdir -p "$REPO/lib/models"
mkdir -p "$REPO/lib/providers"
mkdir -p "$REPO/lib/services"
mkdir -p "$REPO/lib/screens"
mkdir -p "$REPO/lib/widgets"
mkdir -p "$REPO/.github/workflows"
mkdir -p "$REPO/android/app"
mkdir -p "$REPO/android/gradle/wrapper"

# ── Write files ──────────────────────────────────────────────────────────────
# pubspec.yaml
printf '%s' "" | base64 -d > "$REPO/pubspec.yaml"
echo "  written: pubspec.yaml"

# lib/main.dart
printf '%s' "" | base64 -d > "$REPO/lib/main.dart"
echo "  written: lib/main.dart"

# lib/models/pdf_text_block.dart
printf '%s' "" | base64 -d > "$REPO/lib/models/pdf_text_block.dart"
echo "  written: lib/models/pdf_text_block.dart"

# lib/models/annotation_model.dart
printf '%s' "" | base64 -d > "$REPO/lib/models/annotation_model.dart"
echo "  written: lib/models/annotation_model.dart"

# lib/models/pdf_document_model.dart
printf '%s' "" | base64 -d > "$REPO/lib/models/pdf_document_model.dart"
echo "  written: lib/models/pdf_document_model.dart"

# lib/providers/pdf_provider.dart
printf '%s' "" | base64 -d > "$REPO/lib/providers/pdf_provider.dart"
echo "  written: lib/providers/pdf_provider.dart"

# lib/services/pdf_service.dart
printf '%s' "" | base64 -d > "$REPO/lib/services/pdf_service.dart"
echo "  written: lib/services/pdf_service.dart"

# lib/screens/editor_screen.dart
printf '%s' "" | base64 -d > "$REPO/lib/screens/editor_screen.dart"
echo "  written: lib/screens/editor_screen.dart"

# lib/screens/home_screen.dart
printf '%s' "" | base64 -d > "$REPO/lib/screens/home_screen.dart"
echo "  written: lib/screens/home_screen.dart"

# lib/widgets/annotation_overlay.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/annotation_overlay.dart"
echo "  written: lib/widgets/annotation_overlay.dart"

# lib/widgets/editor_toolbar.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/editor_toolbar.dart"
echo "  written: lib/widgets/editor_toolbar.dart"

# lib/widgets/annotations_list.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/annotations_list.dart"
echo "  written: lib/widgets/annotations_list.dart"

# lib/widgets/properties_panel.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/properties_panel.dart"
echo "  written: lib/widgets/properties_panel.dart"

# lib/widgets/thumbnail_panel.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/thumbnail_panel.dart"
echo "  written: lib/widgets/thumbnail_panel.dart"

# lib/widgets/page_navigator.dart
printf '%s' "" | base64 -d > "$REPO/lib/widgets/page_navigator.dart"
echo "  written: lib/widgets/page_navigator.dart"

# .github/workflows/build.yml
printf '%s' "" | base64 -d > "$REPO/.github/workflows/build.yml"
echo "  written: .github/workflows/build.yml"

# android/app/build.gradle
printf '%s' "" | base64 -d > "$REPO/android/app/build.gradle"
echo "  written: android/app/build.gradle"

# android/settings.gradle
printf '%s' "" | base64 -d > "$REPO/android/settings.gradle"
echo "  written: android/settings.gradle"

# android/gradle/wrapper/gradle-wrapper.properties
printf '%s' "" | base64 -d > "$REPO/android/gradle/wrapper/gradle-wrapper.properties"
echo "  written: android/gradle/wrapper/gradle-wrapper.properties"

# analysis_options.yaml
printf '%s' "" | base64 -d > "$REPO/analysis_options.yaml"
echo "  written: analysis_options.yaml"

# ── Remove stale generated Freezed files ─────────────────────────────────────
for f in \
  "lib/models/annotation_model.freezed.dart" \
  "lib/models/annotation_model.g.dart" \
  "lib/models/pdf_document_model.freezed.dart" \
  "lib/models/pdf_document_model.g.dart"; do
  if [ -f "$REPO/$f" ]; then
    rm "$REPO/$f"
    echo "  removed stale: $f"
  fi
done

# ── flutter pub get ──────────────────────────────────────────────────────────
echo ""
echo "Running: flutter pub get ..."
cd "$REPO" && flutter pub get

# ── Regenerate Freezed + json_serializable ───────────────────────────────────
echo ""
echo "Running: dart run build_runner build ..."
cd "$REPO" && dart run build_runner build --delete-conflicting-outputs

# ── Done ─────────────────────────────────────────────────────────────────────
echo ""
echo "============================================================"
echo " Migration complete! 20 files written."
echo "============================================================"
echo ""
echo "Next steps:"
echo "  Android : flutter run"
echo "  Windows : flutter config --enable-windows-desktop && flutter run -d windows"
echo ""
echo "Windows self-hosted runners only: enable Developer Mode"
echo "  Settings -> Update & Security -> For developers -> Developer Mode"
echo ""
echo "Backup at: $BACKUP"